+#[test]
+fn summary_table_covers_all_52_gaps() {
+    let doc = load_baseline_doc();
+    let gaps = extract_summary_table_gaps(&doc);
+    assert!(
+        gaps.len() >= 45,
+        "summary table must list >= 45 gaps, found {}",
+        gaps.len()
+    );
+}
